namespace sv_f672ae93389a472991d6ee17e33ed835.Models;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);

public record NotificationPrefs(
    bool EmailNotifications,
    bool PushNotifications,
    bool WeeklyDigest,
    List<string> MutedChannels);

public record SecuritySettings(
    bool TwoFactorEnabled,
    DateTime? LastPasswordChange,
    List<ActiveSession> Sessions);

public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);

public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

.settings-sidebar {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
    padding: 1rem 0;
    min-width: 200px;
}

.sidebar-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1rem;
    border: none;
    background: transparent;
    text-align: left;
    font-size: 0.95rem;
    color: #495057;
    border-radius: 0.5rem;
    cursor: pointer;
    transition: background-color 0.15s, color 0.15s;
}

.sidebar-item:hover {
    background-color: #f0f0f0;
    color: #212529;
}

.sidebar-item.active {
    background-color: #0d6efd;
    color: #fff;
    font-weight: 600;
}

.sidebar-icon {
    font-size: 1.1rem;
}

@using sv_f672ae93389a472991d6ee17e33ed835.Models

<div class="profile-section">
    <h4 class="mb-4">Profile Settings</h4>

    @if (_successMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_successMessage
            <button type="button" class="btn-close" @onclick="() => _successMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label fw-semibold">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>

            <div class="mb-3">
                <label class="form-label fw-semibold">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>

            <div class="mb-3">
                <label class="form-label fw-semibold">Bio</label>
                <textarea class="form-control" rows="4" @bind="_bio"></textarea>
            </div>
        </div>

        <div class="col-md-4">
            <div class="avatar-preview text-center">
                <div class="avatar-frame mb-2">
                    @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                    {
                        <img src="@_avatarUrl" alt="Avatar" class="avatar-img" />
                    }
                    else
                    {
                        <div class="avatar-placeholder">👤</div>
                    }
                </div>
                <small class="text-muted d-block text-truncate" style="max-width: 200px;" title="@_avatarUrl">
                    @(_avatarUrl ?? "No avatar set")
                </small>
            </div>
        </div>
    </div>

    <div class="d-flex gap-2 mt-3">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@_saving">
            Discard Changes
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public UserProfile Profile { get; set; } = default!;
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string? _avatarUrl;
    private bool _saving;
    private string? _successMessage;

    protected override void OnParametersSet()
    {
        if (!_saving)
        {
            LoadFromProfile();
        }
    }

    private void LoadFromProfile()
    {
        _displayName = Profile.DisplayName;
        _email = Profile.Email;
        _bio = Profile.Bio;
        _avatarUrl = Profile.AvatarUrl;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl ?? "", _bio);
            await OnSave.InvokeAsync(updated);
            _successMessage = "Profile saved successfully!";
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        LoadFromProfile();
        _successMessage = null;
    }
}

.avatar-frame {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    overflow: hidden;
    border: 3px solid #dee2e6;
    margin: 0 auto;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #f8f9fa;
}

.avatar-img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    font-size: 3rem;
    color: #adb5bd;
}

@using sv_f672ae93389a472991d6ee17e33ed835.Models

<div class="notifications-section">
    <h4 class="mb-4">Notification Preferences</h4>

    @if (_successMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_successMessage
            <button type="button" class="btn-close" @onclick="() => _successMessage = null"></button>
        </div>
    }

    <div class="card mb-3">
        <div class="card-body">
            <h6 class="card-title mb-3">General</h6>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
                <div class="form-text">Receive notifications via email</div>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
                <div class="form-text">Receive push notifications in your browser</div>
            </div>

            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
                <div class="form-text">Receive a weekly summary email</div>
            </div>
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-body">
            <h6 class="card-title mb-3">Muted Channels</h6>
            <p class="text-muted small">Uncheck channels you want to mute.</p>

            @if (AvailableChannels.Count == 0)
            {
                <p class="text-muted">No channels available.</p>
            }
            else
            {
                @foreach (var channel in AvailableChannels)
                {
                    <div class="form-check mb-2">
                        <input class="form-check-input"
                               type="checkbox"
                               id="@($"ch-{channel}")"
                               checked="@(!_mutedChannels.Contains(channel))"
                               @onchange="(e) => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                    </div>
                }
            }
        </div>
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
        @if (_saving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Preferences
    </button>
</div>

@code {
    [Parameter, EditorRequired] public NotificationPrefs Prefs { get; set; } = default!;
    [Parameter] public List<string> AvailableChannels { get; set; } = [];
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private bool _saving;
    private string? _successMessage;

    protected override void OnParametersSet()
    {
        if (!_saving)
        {
            _emailNotifications = Prefs.EmailNotifications;
            _pushNotifications = Prefs.PushNotifications;
            _weeklyDigest = Prefs.WeeklyDigest;
            _mutedChannels = [.. Prefs.MutedChannels];
        }
    }

    private void ToggleChannel(string channel, bool enabled)
    {
        if (enabled)
            _mutedChannels.Remove(channel);
        else
            _mutedChannels.Add(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        try
        {
            var updated = new NotificationPrefs(
                _emailNotifications,
                _pushNotifications,
                _weeklyDigest,
                [.. _mutedChannels]);
            await OnSave.InvokeAsync(updated);
            _successMessage = "Notification preferences saved!";
        }
        finally
        {
            _saving = false;
        }
    }
}

.modal-backdrop-custom {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1050;
}

.modal-dialog-custom {
    background: #fff;
    border-radius: 0.5rem;
    max-width: 450px;
    width: 90%;
    box-shadow: 0 0.5rem 1rem rgba(0, 0, 0, 0.15);
}

@using sv_f672ae93389a472991d6ee17e33ed835.Models

<div class="card mb-3">
    <div class="card-body">
        <h6 class="card-title mb-3">Active Sessions</h6>
        <div class="table-responsive">
            <table class="table table-hover align-middle mb-0">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th class="text-end">Action</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("g")</td>
                            <td class="text-end">
                                @if (session.Id == CurrentSessionId)
                                {
                                    <span class="badge bg-success">Current</span>
                                }
                                else
                                {
                                    <button class="btn btn-outline-danger btn-sm"
                                            @onclick="() => OnRevokeRequested.InvokeAsync(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                    @if (Sessions.Count == 0)
                    {
                        <tr>
                            <td colspan="4" class="text-muted text-center">No active sessions.</td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string? CurrentSessionId { get; set; }
    [Parameter] public EventCallback<ActiveSession> OnRevokeRequested { get; set; }
}

@using sv_f672ae93389a472991d6ee17e33ed835.Models

<div class="security-section">
    <h4 class="mb-4">Security Settings</h4>

    <ChangePasswordPanel OnChangePassword="OnChangePassword" />

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <p class="text-muted small mb-0">
                        Add an extra layer of security to your account.
                    </p>
                </div>
                <div class="d-flex align-items-center gap-2">
                    <span class="badge @(Settings.TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(Settings.TwoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
            </div>
            @if (Settings.LastPasswordChange.HasValue)
            {
                <hr />
                <small class="text-muted">
                    Last password change: @Settings.LastPasswordChange.Value.ToString("D")
                </small>
            }
        </div>
    </div>

    <ActiveSessionsTable Sessions="Settings.Sessions"
