@using sv_f672ae93389a472991d6ee17e33ed835.Models

<div class="card mb-3">
    <div class="card-body">
        <h6 class="card-title mb-3">Active Sessions</h6>
        <div class="table-responsive">
            <table class="table table-hover align-middle mb-0">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th class="text-end">Action</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("g")</td>
                            <td class="text-end">
                                @if (session.Id == CurrentSessionId)
                                {
                                    <span class="badge bg-success">Current</span>
                                }
                                else
                                {
                                    <button class="btn btn-outline-danger btn-sm"
                                            @onclick="() => OnRevokeRequested.InvokeAsync(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                    @if (Sessions.Count == 0)
                    {
                        <tr>
                            <td colspan="4" class="text-muted text-center">No active sessions.</td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string? CurrentSessionId { get; set; }
    [Parameter] public EventCallback<ActiveSession> OnRevokeRequested { get; set; }
}

@using sv_f672ae93389a472991d6ee17e33ed835.Models

<div class="security-section">
    <h4 class="mb-4">Security Settings</h4>

    <ChangePasswordPanel OnChangePassword="OnChangePassword" />

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <p class="text-muted small mb-0">
                        Add an extra layer of security to your account.
                    </p>
                </div>
                <div class="d-flex align-items-center gap-2">
                    <span class="badge @(Settings.TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(Settings.TwoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
            </div>
            @if (Settings.LastPasswordChange.HasValue)
            {
                <hr />
                <small class="text-muted">
                    Last password change: @Settings.LastPasswordChange.Value.ToString("D")
                </small>
            }
        </div>
    </div>

    <ActiveSessionsTable Sessions="Settings.Sessions"
                         CurrentSessionId="@CurrentSessionId"
                         OnRevokeRequested="ShowRevokeDialog" />

    <RevokeSessionDialog Session="_sessionToRevoke"
                         OnConfirm="ConfirmRevokeAsync"
                         OnCancel="CancelRevoke" />
</div>

@code {
    [Parameter, EditorRequired] public SecuritySettings Settings { get; set; } = default!;
    [Parameter] public string? CurrentSessionId { get; set; }
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private ActiveSession? _sessionToRevoke;

    private void ShowRevokeDialog(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private async Task ConfirmRevokeAsync(string sessionId)
    {
        await OnRevokeSession.InvokeAsync(sessionId);
        _sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }
}

@using sv_f672ae93389a472991d6ee17e33ed835.Models

<div class="appearance-section">
    <h4 class="mb-4">Appearance Settings</h4>

    @if (_successMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_successMessage
            <button type="button" class="btn-close" @onclick="() => _successMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-7">
            <div class="card mb-3">
                <div class="card-body">
                    <h6 class="card-title mb-3">Theme</h6>
                    @foreach (var theme in _themes)
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")"
                                   value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-body">
                    <h6 class="card-title mb-3">Font Size</h6>
                    @foreach (var size in _fontSizes)
                    {
                        <div class="form-check form-check-inline">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")"
                                   value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-body">
                    <h6 class="card-title mb-3">Language</h6>
                    <select class="form-select" @bind="_language">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang.Value">@lang.Label</option>
                        }
                    </select>
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-body">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                        <label class="form-check-label" for="compactMode">
                            <strong>Compact Mode</strong>
                        </label>
                        <div class="form-text">Reduce spacing and padding throughout the interface</div>
                    </div>
                </div>
            </div>
        </div>

        <div class="col-md-5">
            <div class="card sticky-top" style="top: 1rem;">
                <div class="card-header">
                    <h6 class="mb-0">Live Preview</h6>
                </div>
                <div class="card-body preview-area @PreviewThemeClass" style="@PreviewFontStyle">
                    <div class="preview-header @(_compactMode ? "compact" : "")">
                        <strong>Sample Header</strong>
                    </div>
                    <div class="preview-body @(_compactMode ? "compact" : "")">
                        <p class="mb-2">This is a preview of how your content will look with the selected settings.</p>
                        <div class="d-flex gap-2">
                            <span class="badge bg-primary">Tag</span>
                            <span class="badge bg-secondary">Label</span>
                        </div>
                    </div>
                    <div class="preview-footer @(_compactMode ? "compact" : "")">
                        <small class="text-muted">Theme: @_theme · Size: @_fontSize · @SelectedLanguageLabel</small>
                    </div>
                </div>
            </div>
        </div>
    </div>

    <button class="btn btn-primary mt-2" @onclick="SaveAsync" disabled="@_saving">
        @if (_saving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save
    </button>
</div>

@code {
    [Parameter, EditorRequired] public AppearanceSettings Settings { get; set; } = default!;
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;
    private bool _saving;
    private string? _successMessage;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly (string Value, string Label)[] _languages =
    [
        ("en", "English"),
        ("es", "Español"),
        ("fr", "Français"),
        ("de", "Deutsch"),
        ("ja", "日本語"),
        ("zh", "中文")
    ];

    private string PreviewThemeClass => _theme switch
    {
        "Dark" => "preview-dark",
        _ => "preview-light"
    };

    private string PreviewFontStyle => _fontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;"
    };

    private string SelectedLanguageLabel =>
        _languages.FirstOrDefault(l => l.Value == _language).Label ?? _language;

    protected override void OnParametersSet()
    {
        if (!_saving)
        {
            _theme = Settings.Theme;
            _fontSize = Settings.FontSize;
            _language = Settings.Language;
            _compactMode = Settings.CompactMode;
        }
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        try
        {
            var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await OnSave.InvokeAsync(updated);
            _successMessage = "Appearance settings saved!";
        }
        finally
        {
            _saving = false;
        }
    }
}

