@page "/settings"
@rendermode InteractiveServer
@using sv_f672ae93389a472991d6ee17e33ed835.Models
@using sv_f672ae93389a472991d6ee17e33ed835.Components.Settings

@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    @if (_loading)
    {
        <div class="d-flex justify-content-center align-items-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading settings…</span>
            </div>
        </div>
    }
    else if (_error is not null)
    {
        <div class="alert alert-danger m-4">
            <strong>Error loading settings:</strong> @_error
            <button class="btn btn-link" @onclick="LoadAllAsync">Retry</button>
        </div>
    }
    else
    {
        <div class="settings-layout">
            <aside class="settings-nav">
                <h5 class="px-3 pt-3 pb-2 mb-0">Settings</h5>
                <SettingsSidebar ActiveSection="@_activeSection"
                                OnSectionChanged="s => _activeSection = s" />
            </aside>

            <main class="settings-content">
                @switch (_activeSection)
                {
                    case "Profile":
                        <ProfileSection Profile="_profile!"
                                        OnSave="SaveProfileAsync" />
                        break;

                    case "Notifications":
                        <NotificationsSection Prefs="_notifications!"
                                              AvailableChannels="_allChannels"
                                              OnSave="SaveNotificationsAsync" />
                        break;

                    case "Security":
                        <SecuritySection Settings="_security!"
                                         CurrentSessionId="@_currentSessionId"
                                         OnChangePassword="ChangePasswordAsync"
                                         OnRevokeSession="RevokeSessionAsync" />
                        break;

                    case "Appearance":
                        <AppearanceSection Settings="_appearance!"
                                           OnSave="SaveAppearanceAsync" />
                        break;
                }
            </main>
        </div>
    }
</div>

@code {
    private string _activeSection = "Profile";
    private bool _loading = true;
    private string? _error;

    private UserProfile? _profile;
    private NotificationPrefs? _notifications;
    private SecuritySettings? _security;
    private AppearanceSettings? _appearance;
    private List<string> _allChannels = [];
    private string? _currentSessionId;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllAsync();
    }

    private async Task LoadAllAsync()
    {
        _loading = true;
        _error = null;
        try
        {
            var profileTask = SettingsService.GetProfileAsync();
            var notifTask = SettingsService.GetNotificationPrefsAsync();
            var securityTask = SettingsService.GetSecuritySettingsAsync();
            var appearanceTask = SettingsService.GetAppearanceAsync();

            await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

            _profile = profileTask.Result;
            _notifications = notifTask.Result;
            _security = securityTask.Result;
            _appearance = appearanceTask.Result;

            // Derive available channels from whatever is currently known
            _allChannels = [.. _notifications.MutedChannels.Union(
                new[] { "general", "announcements", "engineering", "design", "random" })
                .OrderBy(c => c)];

            // Use first session as current if available
            _currentSessionId = _security.Sessions.FirstOrDefault()?.Id;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SaveProfileAsync(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        _profile = profile;
    }

    private async Task SaveNotificationsAsync(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _notifications = prefs;
    }

    private async Task ChangePasswordAsync((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        // Refresh security settings to get updated LastPasswordChange
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        _appearance = settings;
    }
}

